import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o,c as r,a as n,b as t,d as s,f as l}from"./app-0a32ec83.js";const p="/assets/img/qwen_2/image-20240804181902916.png",c="/assets/img/qwen_2/image-20240804181521807.png",g="/assets/img/qwen_2/image-20240804181557764.png",d="/assets/img/qwen_2/image-20250916082357105.png",u="/assets/img/qwen_2/image-20250916082328594.png",m="/assets/img/qwen_2/image-20250917213049278.png",y="/assets/img/qwen_2/image-20250917215024691.png",h="/assets/img/qwen_2/image-20250917220105180.png",q="/assets/img/qwen_2/image-20250915144034934.png",f="/assets/img/qwen_2/image-20250917222744709.png",b="/assets/img/qwen_2/image-20250222115257990.png",_="/assets/img/qwen_2/image-20250223131425276.png",v="/assets/img/qwen_2/image-20250223131927556.png",w="/assets/img/qwen_2/image-20250513131731479.png",x="/assets/img/qwen_2/image-20250513143457926.png",E="/assets/img/qwen_2/image-20250513143647500.png",Q="/assets/img/qwen_2/image-20250513143659154.png",L="/assets/img/qwen_2/image-20250502172950746.png",F="/assets/img/qwen_2/image-20250926191238455.png",C="/assets/img/qwen_2/image-20250926191209997.png",k="/assets/img/qwen_2/image-20250926191522773.png",B="/assets/img/qwen_2/image-20250926210340004.png",V="/assets/img/qwen_2/image-20251003180801340.png",M="/assets/img/qwen_2/image-20251003180825593.png",z="/assets/img/qwen_2/image-20251003194211288.png",T="/assets/img/qwen_2/image-20251003204024670.png",A="/assets/img/qwen_2/image-20251007115502377.png",P={},R=n("p",null,"针对 2024 年左右的 Qwen 模型的一些要点记录",-1),D=n("hr",null,null,-1),O=n("h2",{id:"qwen-1-5-系列",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#qwen-1-5-系列","aria-hidden":"true"},"#"),t(" Qwen 1.5 系列")],-1),I={href:"https://huggingface.co/collections/Qwen/qwen15-65c0a2f577b1ecb76d786524",target:"_blank",rel:"noopener noreferrer"},S={href:"https://qwenlm.github.io/zh/blog/qwen1.5/",target:"_blank",rel:"noopener noreferrer"},H={href:"https://qwenlm.github.io/zh/blog/qwen1.5-32b/",target:"_blank",rel:"noopener noreferrer"},G=l('<p>发布时间：24 年 2 月。</p><p>模型大小：包括 0.5B, 1.8B, 4B, 7B, 14B, 32B and 72B dense 模型，以及 MoE-A2.7B 模型。</p><p>架构：32B 以上的模型用了 GQA，其他架构大致相同。</p><p>训练：</p><ul><li>RLHF：直接策略优化（DPO）和近端策略优化（PPO）等技术。</li><li>长序列：全系列支持 32K+ tokens 的上下文</li></ul><p>数据：</p><ul><li>挑选了来自欧洲、东亚和东南亚的 12 种不同语言</li></ul><p>官方给出的评分：</p><table><thead><tr><th style="text-align:left;">Model</th><th style="text-align:center;">MMLU</th><th style="text-align:center;">C-Eval</th><th style="text-align:center;">GSM8K</th><th style="text-align:center;">MATH</th><th style="text-align:center;">HumanEval</th><th style="text-align:center;">MBPP</th><th style="text-align:center;">BBH</th><th style="text-align:center;">CMMLU</th></tr></thead><tbody><tr><td style="text-align:left;">GPT-4</td><td style="text-align:center;">86.4</td><td style="text-align:center;">69.9</td><td style="text-align:center;">92.0</td><td style="text-align:center;">45.8</td><td style="text-align:center;">67.0</td><td style="text-align:center;">61.8</td><td style="text-align:center;">86.7</td><td style="text-align:center;">71.0</td></tr><tr><td style="text-align:left;">Llama2-7B</td><td style="text-align:center;">46.8</td><td style="text-align:center;">32.5</td><td style="text-align:center;">16.7</td><td style="text-align:center;">3.3</td><td style="text-align:center;">12.8</td><td style="text-align:center;">20.8</td><td style="text-align:center;">38.2</td><td style="text-align:center;">31.8</td></tr><tr><td style="text-align:left;">Llama2-13B</td><td style="text-align:center;">55.0</td><td style="text-align:center;">41.4</td><td style="text-align:center;">29.6</td><td style="text-align:center;">5.0</td><td style="text-align:center;">18.9</td><td style="text-align:center;">30.3</td><td style="text-align:center;">45.6</td><td style="text-align:center;">38.4</td></tr><tr><td style="text-align:left;">Llama2-34B</td><td style="text-align:center;">62.6</td><td style="text-align:center;">-</td><td style="text-align:center;">42.2</td><td style="text-align:center;">6.2</td><td style="text-align:center;">22.6</td><td style="text-align:center;">33.0</td><td style="text-align:center;">44.1</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">Llama2-70B</td><td style="text-align:center;">69.8</td><td style="text-align:center;">50.1</td><td style="text-align:center;">54.4</td><td style="text-align:center;">10.6</td><td style="text-align:center;">23.7</td><td style="text-align:center;">37.7</td><td style="text-align:center;">58.4</td><td style="text-align:center;">53.6</td></tr><tr><td style="text-align:left;">Mistral-7B</td><td style="text-align:center;">64.1</td><td style="text-align:center;">47.4</td><td style="text-align:center;">47.5</td><td style="text-align:center;">11.3</td><td style="text-align:center;">27.4</td><td style="text-align:center;">38.6</td><td style="text-align:center;">56.7</td><td style="text-align:center;">44.7</td></tr><tr><td style="text-align:left;">Mixtral-8x7B</td><td style="text-align:center;">70.6</td><td style="text-align:center;">-</td><td style="text-align:center;">74.4</td><td style="text-align:center;">28.4</td><td style="text-align:center;">40.2</td><td style="text-align:center;">60.7</td><td style="text-align:center;">-</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">Qwen1.5-7B</td><td style="text-align:center;">61.0</td><td style="text-align:center;">74.1</td><td style="text-align:center;">62.5</td><td style="text-align:center;">20.3</td><td style="text-align:center;">36.0</td><td style="text-align:center;">37.4</td><td style="text-align:center;">40.2</td><td style="text-align:center;">73.1</td></tr><tr><td style="text-align:left;">Qwen1.5-14B</td><td style="text-align:center;">67.6</td><td style="text-align:center;">78.7</td><td style="text-align:center;">70.1</td><td style="text-align:center;">29.2</td><td style="text-align:center;">37.8</td><td style="text-align:center;">44.0</td><td style="text-align:center;">53.7</td><td style="text-align:center;">77.6</td></tr><tr><td style="text-align:left;">Qwen1.5-32B</td><td style="text-align:center;">73.4</td><td style="text-align:center;">83.5</td><td style="text-align:center;">77.4</td><td style="text-align:center;">36.1</td><td style="text-align:center;">37.2</td><td style="text-align:center;">49.4</td><td style="text-align:center;">66.8</td><td style="text-align:center;">82.3</td></tr><tr><td style="text-align:left;">Qwen1.5-72B</td><td style="text-align:center;">77.5</td><td style="text-align:center;">84.1</td><td style="text-align:center;">79.5</td><td style="text-align:center;">34.1</td><td style="text-align:center;">41.5</td><td style="text-align:center;">53.4</td><td style="text-align:center;">65.5</td><td style="text-align:center;">83.5</td></tr></tbody></table>',9),W={href:"https://qwenlm.github.io/zh/blog/qwen-moe/",target:"_blank",rel:"noopener noreferrer"},j=n("p",null,"Qwen 1.5 MOE 对 Mixtral MOE 的架构进行了优化，包括 Finegrained experts，初始化，新的 routing 机制等。更多欢迎参考 https://qwenlm.github.io/zh/blog/qwen-moe/",-1),N=n("hr",null,null,-1),K=n("h2",{id:"qwen-2-系列",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#qwen-2-系列","aria-hidden":"true"},"#"),t(" Qwen 2 系列")],-1),Y={href:"https://arxiv.org/abs/2407.10671",target:"_blank",rel:"noopener noreferrer"},U=l('<p><strong>架构：</strong> Dense 模型及 MOE 模型与 Qwen 1.5 对应版本的架构一样。</p><p><strong>模型大小：</strong> 有 0.5B，1.5B，7B 和 72B 四种 dense 模型；同时还有一个 57B-A14B 的 MOE。</p><p><strong>预训练：</strong> 训练数据 一共有 7T，包含了 30 种语言，数据中收集了更多高质量的代码、数学和多语种数据。</p><p><strong>超长上下文：</strong> 先用 4096 的长度训练，而后再训练结束前，换成 32K。采用了 YARN 和 Dual Chunk Attention。以下为大海捞针评测：</p><figure><img src="'+p+'" alt="image-20240804181902916" tabindex="0" loading="lazy"><figcaption>image-20240804181902916</figcaption></figure><p><strong>SFT：</strong> 用了超过 500K 的实例进行训练，数据集中包含指令遵循，代码，数学，逻辑推理，角色扮演，安全等数据。finetune 了 2 个 epoch，训练文本长度限制再了 32K。</p><p><strong>RLHF：</strong></p><ul><li><strong>离线训练：</strong> 用 DPO 再标注好的偏好数据集上训练。</li><li><strong>在线训练：</strong> 同样采用 DPO，同时采用 Online Merging Optimizer 来缓解对齐税。</li></ul><p><strong>模型效果：</strong></p><p>Qwen2 72B 效果：</p><figure><img src="'+c+'" alt="image-20240804181521807" tabindex="0" loading="lazy"><figcaption>image-20240804181521807</figcaption></figure><p>Qwen2 7B 效果：</p><figure><img src="'+g+'" alt="image-20240804181557764" tabindex="0" loading="lazy"><figcaption>image-20240804181557764</figcaption></figure>',13),X={href:"https://qwenlm.github.io/zh/blog/qwen2/",target:"_blank",rel:"noopener noreferrer"},J=l('<hr><h2 id="qwen-audio" tabindex="-1"><a class="header-anchor" href="#qwen-audio" aria-hidden="true">#</a> Qwen-Audio</h2><p>Arxiv: https://arxiv.org/pdf/2311.07919</p><p>23 年发布的模型，再当时就有了一定的语音理解能力。</p><figure><img src="'+d+'" alt="image-20250916082357105" tabindex="0" loading="lazy"><figcaption>image-20250916082357105</figcaption></figure><p>模型架构如下，</p><ul><li>audio encoder 采用 Whisper-large-v2（32 层 transformer+2 个 Conv Down-sampling Layer），采样率 16KHz；音频被处理成 80 channel 的 mel spectrogram。</li><li>QwenLM 采用 Qwen-7B</li></ul><figure><img src="'+u+'" alt="image-20250916082328594" tabindex="0" loading="lazy"><figcaption>image-20250916082328594</figcaption></figure><p>预训练</p><p>预训练采用了 multitask pretraining，预训练的数据集如下：</p><figure><img src="'+m+'" alt="image-20250917213049278" tabindex="0" loading="lazy"><figcaption>image-20250917213049278</figcaption></figure><p>Whispher 模型中，有上下文标记（special token）来处理不同任务，比如说语言检测，翻译，等等。Qwen-Audio 也采用了相似的处理方式，加入了不同的 tags，可以参考上方的架构图中的 tags：</p><ul><li>采用 Transcription Tag：预测的开始由转录标签表示。使用 <code>&lt;|startoftranscripts|&gt;</code> 标签来表明任务是准确转录语音内容并捕捉语言信息，例如语音识别和语音翻译任务。而对于其他类型的任务，则使用 <code>&lt;|startofanalysis|&gt;</code> 标签。</li><li>采用 Audio Language Tag：用于指示音频中的口语语言。这个标签使用一个唯一的标记，对应训练集中出现的每种语言（共八种语言）。如果某段音频中不包含语音，例如自然声音或音乐，模型会被训练去预测 <code>&lt;|unknown|&gt;</code> 标签。</li><li>Task Tag：将采集的音频任务分为五类：<code>&lt;|transcribe|&gt;</code>、<code>&lt;|translate|&gt;</code>、<code>&lt;|caption|&gt;</code>、<code>&lt;|analysis|&gt;</code> 和 <code>&lt;|question-answer|&gt;</code> 任务。对于问答（QA）任务，会在标签后附加相应的问题。</li><li>Text Language Tag：制定需要输出的语言类型。</li><li>Timestamps Tag：时间戳的有无由 <code>&lt;|timestamps|&gt;</code> 或 <code>&lt;|notimestamps|&gt;</code> 标签决定。与 Whisper 中的句级时间戳不同，<code>&lt;|timestamps|&gt;</code> 标签要求模型进行细粒度的词级时间戳预测（SRWT，Speech Recognition with Word-level Timestamps）。在这种模式下，预测的时间戳与转录词交错：在每个转录词之前预测开始时间标记，在其之后预测结束时间标记。根据我们的实验，SRWT 提升了模型对音频信号与时间戳的对齐能力。这种改进使模型对语音信号的理解更加全面，从而在语音识别和音频问答等多项任务中取得显著进步。</li><li>Output Instruction：输出指令</li></ul><p>微调</p><p>采用了下面这种 instruction 方式构造 template，总共训练数据是 20K</p><figure><img src="'+y+'" alt="image-20250917215024691" tabindex="0" loading="lazy"><figcaption>image-20250917215024691</figcaption></figure><p>可以看到在各种任务上，Qwen-Audio 在当时的效果还是不错的：</p><figure><img src="'+h+'" alt="image-20250917220105180" tabindex="0" loading="lazy"><figcaption>image-20250917220105180</figcaption></figure><hr><h2 id="qwen2-audio" tabindex="-1"><a class="header-anchor" href="#qwen2-audio" aria-hidden="true">#</a> Qwen2-Audio</h2><p>arxiv: https://arxiv.org/abs/2407.10759</p><p>24 年 8 月左右进行了 Qwen2-Audio 的更新</p><figure><img src="'+q+'" alt="image-20250915144034934" tabindex="0" loading="lazy"><figcaption>image-20250915144034934</figcaption></figure><p><strong>架构</strong></p><ul><li>Audio Encoder 通过 Whisper-large-v3 初始化，采样频率 16kHz，转换成 128 channel 的梅尔频谱（window size 25ms, hop size 10 ms)；同时采用 pooling layer（stride 2）来减少表征的长度。</li></ul><p><strong>预训练：</strong></p><ul><li>与 Qwen-Audio 的差别很大，在这一代中取消了 tags 的处理，使用了自然语言 prompt 来进行训练，可以参考上面架构图中的例子。</li><li>370k 数据为 speech，10k 为 sound，140k 为 music。</li></ul><p><strong>SFT</strong></p><p>分了 2 中不同的交互模式，两种模式是同时训练的：</p><ul><li>Audio Analysis：通常用于线下的音频分析。</li><li>Voice Chat：通常用于实时对话。</li></ul><p><strong>RLHF：</strong></p><ul><li>采用了 DPO</li></ul><figure><img src="'+f+'" alt="image-20250917222744709" tabindex="0" loading="lazy"><figcaption>image-20250917222744709</figcaption></figure><hr><h2 id="qwen-vl" tabindex="-1"><a class="header-anchor" href="#qwen-vl" aria-hidden="true">#</a> Qwen-VL</h2><p>论文：https://arxiv.org/pdf/2308.12966</p><p>效果：23 年提出的 VL 版本已经表现出了一定的 instruction following 能力，以及 in context learning 能力，并且模型具备一定的理解图片能力。qwen VL 在训练之后，似乎纯文字能力并没有降低。</p><p>潜在的优化点：learnable query 的作用类似于连续型的 prompt，直觉上看，增加多类型预训练任务能够提高模型在推理时候的泛化能力。参考 GPT-3 以及 FLAN 系列模型的对比，应该有比 learnable query 更好的图片 embedding 方式。图片 embedding 似乎永远放在了最前面，图片像素限制容易丢失信息。</p><p><strong>模型架构：</strong></p><p><strong>Vistion Encoer:</strong></p><ul><li>采用 Openclip’s ViT-bigG 的预训练权重。</li><li>推理和训练时候，图像会 resize 到特定的像素。</li><li>VIT 将图片转化为 patch 时候，采用了 14 的 stride</li></ul><p><strong>Position-aware Vision-Language Adapter</strong></p><ul><li>该适配器由一个随机初始化的单层交叉注意力模块组成，该模块使用一组可训练向量（Embedding）作为查询向量 ，并将来自视觉编码器的图像特征作为键进行交叉注意力操作，从而将视觉特征序列压缩至固定长度 256。</li><li>为了弥补压缩过程中丢失掉的位置信息，cross-attension 中加入了 2D absolute positional encodings</li></ul><p><strong>Large Language Model</strong></p><ul><li>采用了 Qwen-7B 作为 LLM。</li></ul><p><strong>输入输出样式：</strong></p><ul><li>添加了<code>&lt;img&gt; and &lt;/img&gt;</code> token 来标记图像 feature。</li><li>训练过程中加入了 bbox 和对应 reference 的信息，并用 <code>(&lt;ref&gt; and &lt;/ref&gt;) </code> 以及 <code>&lt;box&gt; and &lt;/box&gt;</code> 来标记。</li></ul><p><strong>总体训练架构如下，训练分为 3 步：</strong></p><figure><img src="'+b+'" alt="image-20250222115257990" tabindex="0" loading="lazy"><figcaption>image-20250222115257990</figcaption></figure><ul><li>第一步：预训练数据分布（数据为 224x224 image-text pair，共 1.4 billion）冻结 LLM 只训练 Vision encoder 和 VL adapter：优化目标，NTP</li></ul><figure><img src="'+_+'" alt="image-20250223131425276" tabindex="0" loading="lazy"><figcaption>image-20250223131425276</figcaption></figure><ul><li>第二部：multi-task pretraining。input image 大小增大到 448x448。整个模型都进行优化，优化目标和第一阶段一样。</li></ul><figure><img src="'+v+'" alt="image-20250223131927556" tabindex="0" loading="lazy"><figcaption>image-20250223131927556</figcaption></figure><p>训练数据格式如下：</p><figure><img src="'+w+`" alt="image-20250513131731479" tabindex="0" loading="lazy"><figcaption>image-20250513131731479</figcaption></figure><p>其中比较有意思的是 <code>&lt;ref&gt;</code> 以及 <code>&lt;box&gt;</code> 的使用方式，有点用点读机教小朋友的感觉。</p><ul><li>第三步：SFT。数据数量共 350k，数据格式如下，只训练 LLM 部分：</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292e;">&lt;im_start&gt;user </span></span>
<span class="line"><span style="color:#24292e;">Picture 1: &lt;img&gt;vg/VG_100K_2/649.jpg&lt;/img&gt;What is the sign in the picture?&lt;im_end&gt;</span></span>
<span class="line"><span style="color:#24292e;">&lt;im_start&gt;assistant The sign is a road closure with an orange rhombus.&lt;im_end&gt; </span></span>
<span class="line"><span style="color:#24292e;">&lt;im_start&gt;user How is the weather in the picture?&lt;im_end&gt; </span></span>
<span class="line"><span style="color:#24292e;">&lt;im_start&gt;assistant The shape of the road closure sign is an orange rhombus.&lt;im_end&gt;</span></span>
<span class="line"><span style="color:#24292e;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="qwen2-vl" tabindex="-1"><a class="header-anchor" href="#qwen2-vl" aria-hidden="true">#</a> Qwen2-VL</h2><p>官方博客：https://qwenlm.github.io/zh/blog/qwen2-vl/</p><p>论文：https://arxiv.org/pdf/2409.12191</p><p>huggingface：https://huggingface.co/collections/Qwen/qwen2-vl-66cee7455501d7126940800d</p><p>主要特点：模型提供了 2B， 7B， 72B 三种尺寸； <strong>支持不同分辨率图片，支持视频理解，能操控手机或机器人。</strong></p><ol><li><strong>读懂不同分辨率和不同长宽比的图片</strong> ：Qwen2-VL 在 MathVista、DocVQA、RealWorldQA、MTVQA 等视觉理解基准测试中取得了全球领先的表现。</li><li><strong>理解 20 分钟以上的长视频</strong> ：Qwen2-VL 可理解长视频，并将其用于基于视频的问答、对话和内容创作等应用中。</li><li><strong>能够操作手机和机器人的视觉智能体</strong> ：借助复杂推理和决策的能力，Qwen2-VL 可集成到手机、机器人等设备，根据视觉环境和文字指令进行自动操作。</li><li><strong>多语言支持</strong> ：为了服务全球用户，除英语和中文外，Qwen2-VL 现在还支持理解图像中的多语言文本，包括大多数欧洲语言、日语、韩语、阿拉伯语、越南语等。</li></ol><p>官方博客中有示例，可以看出 qwen2-vl 可以理解颜色，位置，文字内容等图片内容。同时可以根据这些内容进行一定的推理。此外还具备视频理解功能，根据官方提供的视频理解示例，Qwen2-vl 可以做到实时视频聊天。此外，qwen2-vl 还加入了 function calling 功能，有了 function call 后，就可以实现一些如智能体控制屏幕的功能。当然官方表示这些功能还都不是很完美。</p><p>模型架构：</p><ul><li>Qwen2-VL 在架构上的一大改进是 <strong>修改了图像编码器</strong> ，实现了对 <strong>原生动态分辨率</strong> 的全面支持。与上一代模型相比，Qwen2-VL 能够处理任意分辨率的图像输入，不同大小图片被转换为动态数量的 tokens，最小只占 4 个 tokens。 <ul><li>修改了 vit 中的绝对位置编码，改为了 2D-RoPE，</li><li>用 <code>&lt;|vision_start|&gt; and &lt;|vision_end|&gt;</code> 来区分图片信息。</li><li>使用 1 个 MLP 层压缩 VIT 的输出，来限制 token 数量。MLP 将临近的 2*2 的 token 转换为 1 个 token。比如 224 乘 224 的图片，如果 patch size = 14 的话，图片会被压缩成 66 个 token （224/14 * 224/14 / 4 + 2）。</li><li>对于视频输入，采用了 3D 的 2x2 Conv 层来进行 embedding。（16 * 336/14 * 644/14 / 8 = 2208）</li><li>参考下图的架构，似乎图片编码可以放在任意的位置。</li></ul></li></ul><figure><img src="https://qianwen-res.oss-cn-beijing.aliyuncs.com/Qwen2-VL/qwen2_vl.jpg#center" alt="0" tabindex="0" loading="lazy"><figcaption>0</figcaption></figure><ul><li>Qwen2-VL 在架构上的另一重要创新则是 <strong>多模态旋转位置嵌入（M-ROPE）</strong> ，M-ROPE 通过将原始旋转嵌入分解为代表时间、高度和宽度的三个部分，使得大规模语言模型能够同时捕捉和整合一维文本序列、二维视觉图像以及三维视频的位置信息。</li><li>视频理解：每秒 2 帧进行采样。通过 3D Conv （depth=2）来编码。</li></ul><p>输入数据格式如下：</p><figure><img src="`+x+'" alt="image-20250513143457926" tabindex="0" loading="lazy"><figcaption>image-20250513143457926</figcaption></figure><figure><img src="'+E+'" alt="image-20250513143647500" tabindex="0" loading="lazy"><figcaption>image-20250513143647500</figcaption></figure><figure><img src="'+Q+'" alt="image-20250513143659154" tabindex="0" loading="lazy"><figcaption>image-20250513143659154</figcaption></figure><p>训练方法</p><p><strong>主要重点整理：</strong></p><ul><li><strong>三阶段训练方法</strong></li><li>第一阶段：专注训练视觉变换器（ViT），利用海量图像-文本对增强 LLM 的语义理解。</li><li>第二阶段：解冻所有参数，使用更丰富的数据进行全面训练。</li><li>第三阶段：锁定 ViT 参数，利用指令数据集对 LLM 进行专门微调。</li><li><strong>预训练数据集</strong></li><li>数据种类包括：图像-文本对、OCR 数据、交错图文文章、视觉问答数据集、视频对话、图像知识数据集。</li><li>数据来源主要为清洗后的网页、开源数据集和合成数据（数据截止至 2023 年 6 月）。</li><li><strong>初始预训练阶段</strong></li><li>模型处理约 6000 亿个标记。</li><li>LLM 组件初始化采用 Qwen2 参数；视觉编码器初始化使用 DFN 的 ViT，并将固定位置嵌入替换为 RoPE-2D。</li><li>主要任务为学习图像与文本的关系、OCR 文本识别和图像分类。</li><li><strong>第二阶段预训练</strong></li><li>增加 8000 亿个与图像相关的标记，加入更多混合图文内容和视觉问答数据。</li><li>引入多任务数据集，强化模型对复杂视觉-文本交互的理解，同时维持纯文本语言能力。</li><li><strong>总体预训练量与监督</strong></li><li>累计处理 1.4 万亿个标记（包括文本和图像标记，但训练时仅对文本标记提供监督）。</li><li><strong>指令微调阶段</strong></li><li>使用 ChatML 格式构建指令跟随数据，涵盖纯文本及多模态（图像问答、文档解析、多图像比较、视频理解、视频流对话、代理交互）对话数据，提升模型多模态任务执行能力。</li></ul><hr><h2 id="qwen2-5" tabindex="-1"><a class="header-anchor" href="#qwen2-5" aria-hidden="true">#</a> Qwen2.5</h2><p>arxiv: https://arxiv.org/abs/2412.15115</p><p>博客：https://qwenlm.github.io/zh/blog/qwen2.5-llm/</p><p>hugginface：https://huggingface.co/collections/Qwen/qwen25-66e81a666513e518adb90d9e</p><p>24 年 9 月左右推出了 Qwen2.5-LLM，对标模型 llama 3.1 和 GPT-4o-mini</p><p>模型架构：</p><ul><li>模型大小：1.5B、3B、7B、32B、72B；</li><li>架构：dense 模型与 Qwen2 模型类似，采用 GQA + SwiGLU + ROPE + RMSNorm</li><li>tokenizer 采用 byte-level byte-pair encoding （BBPE）</li></ul><p>数据：</p><ul><li>提升到了 <strong>18T</strong> token 预训练数据。采用 Qwen2-Instruct 过滤数据，同时确保每个 domain 上的数据量差不多；预训练添加了 Qwen2.5-Math, 和 Qwen2.5-Coder 的语料，添加了更多数学和代码语料；添使用 Qwen2-72B-Instruct 和 Qwen2-Math-72B-Instruct 生成了一些合成数据集。</li></ul><p>训练：总体训练包括，</p><ul><li>pretraining</li><li>Long-context pre-training，用于拓展上下文， 主要用了 YARN 和 DCA</li><li>post-training: <ul><li><strong>SFT：</strong> 包括了 Long-sequence Generation， Mathematics，Coding，Instruction-following，Structured Data Understanding，Logical Reasoning，Robust System Instruction，Response Filtering 等其他方面的微调。</li><li><strong>Offline Reinforcement Learning：</strong> 用了 DPO。使用 SFT 模型进行采样，采样后样本经过人工+自动化双重筛选，决定是正样本还是负样本。一共有 150k 个训练样本，学习率 <code>7e-7</code></li><li><strong>Online Reinforcement Learning</strong> ：用了 GRPO，用与调整模型在例如 Truthfulness, Helpfulness, Conciseness, Relevance, Harmlessness, Debiasing 相关的能力。</li></ul></li></ul><hr><h2 id="qwq-qwen-with-question" tabindex="-1"><a class="header-anchor" href="#qwq-qwen-with-question" aria-hidden="true">#</a> QwQ - Qwen with Question</h2><p>博客：</p><p>QWQ-32B-preview：https://qwenlm.github.io/zh/blog/qwq-32b-preview/</p><p>QwQ-32B：https://qwenlm.github.io/zh/blog/qwq-32b/</p><p>QwQ-Max-preview：https://qwenlm.github.io/zh/blog/qwq-max-preview/</p><p>huggingface：https://huggingface.co/collections/Qwen/qwq-674762b79b75eac01735070a</p><p>QwQ 系列的模型，强化了推理能力，下图为与 DeepSeek-R1 和 o1 的对比：</p><figure><img src="'+L+`" alt="image-20250502172950746" tabindex="0" loading="lazy"><figcaption>image-20250502172950746</figcaption></figure><p>QwQ-32B：</p><p>模型架构与 Qwen2.5 差不多，比 Qwen2.5 多添加了 <code>&lt;think&gt;</code>, <code>&lt;/think&gt;</code> 之类的符号。</p><p>对于以下 API request</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292E;">{</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;messages&quot;</span><span style="color:#24292E;">:[</span></span>
<span class="line"><span style="color:#24292E;">        {</span><span style="color:#032F62;">&quot;role&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;user&quot;</span><span style="color:#24292E;">, </span><span style="color:#032F62;">&quot;content&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;你好&quot;</span><span style="color:#24292E;">},</span></span>
<span class="line"><span style="color:#24292E;">        {</span><span style="color:#032F62;">&quot;role&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;assistant&quot;</span><span style="color:#24292E;">, </span><span style="color:#032F62;">&quot;content&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;你好！很高兴见到你，有什么我可以帮忙的吗？无论是学习、工作还是生活中的问题，都可以告诉我哦！😊&quot;</span><span style="color:#24292E;">},</span></span>
<span class="line"><span style="color:#24292E;">        {</span><span style="color:#032F62;">&quot;role&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;user&quot;</span><span style="color:#24292E;">, </span><span style="color:#032F62;">&quot;content&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;(10+10) * 13 等于多少&quot;</span><span style="color:#24292E;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">    ],</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;model&quot;</span><span style="color:#24292E;">:</span><span style="color:#032F62;">&quot;gpt-4o-mini&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;temperature&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">0</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;stream&quot;</span><span style="color:#24292E;">: false,</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;max_tokens&quot;</span><span style="color:#24292E;">:</span><span style="color:#005CC5;">200</span></span>
<span class="line"><span style="color:#24292E;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>模型在 completion 情况下，返回的内容是：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292E;">{</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;id&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;chatcmpl-2fd0a9663c0a4dc48b977507fd553ab7&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;object&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;chat.completion&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;created&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">1746191230</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;model&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;gpt-4o-mini&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;choices&quot;</span><span style="color:#24292E;">: [</span></span>
<span class="line"><span style="color:#24292E;">    {</span></span>
<span class="line"><span style="color:#24292E;">      </span><span style="color:#032F62;">&quot;index&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">0</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">      </span><span style="color:#032F62;">&quot;message&quot;</span><span style="color:#24292E;">: {</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#032F62;">&quot;role&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;assistant&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#032F62;">&quot;reasoning_content&quot;</span><span style="color:#24292E;">: null,</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#032F62;">&quot;content&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;&lt;think&gt;</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;"> 首先，计算括号内的 10 加 10，得到 20。</span><span style="color:#005CC5;">\\n\\n</span><span style="color:#032F62;"> 然后，将 20 乘以 13，得到 260。</span><span style="color:#005CC5;">\\n\\n</span><span style="color:#032F62;"> 因此，最终答案是 260。</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">&lt;/think&gt;</span><span style="color:#005CC5;">\\n\\n</span><span style="color:#032F62;"> 要计算 </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">((10 + 10) </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">times 13</span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">)，按照运算顺序进行如下步骤：</span><span style="color:#005CC5;">\\n\\n</span><span style="color:#032F62;">1.  **计算括号内的加法** ：</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">   </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">[</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">   10 + 10 = 20</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">   </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">]</span><span style="color:#005CC5;">\\n\\n</span><span style="color:#032F62;">2.  **将结果乘以 13** ：</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">   </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">[</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">   20 </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">times 13 = 260</span><span style="color:#005CC5;">\\n</span><span style="color:#032F62;">   </span><span style="color:#005CC5;">\\\\</span><span style="color:#032F62;">]</span><span style="color:#005CC5;">\\n\\n</span><span style="color:#032F62;"> 因此，最终答案是：</span><span style="color:#005CC5;">\\n\\\\</span><span style="color:#032F62;">[</span><span style="color:#005CC5;">\\n\\\\</span><span style="color:#032F62;">boxed</span><span style="color:#005CC5;">{260}\\n\\\\</span><span style="color:#032F62;">]&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">        </span><span style="color:#032F62;">&quot;tool_calls&quot;</span><span style="color:#24292E;">: []</span></span>
<span class="line"><span style="color:#24292E;">      },</span></span>
<span class="line"><span style="color:#24292E;">      </span><span style="color:#032F62;">&quot;logprobs&quot;</span><span style="color:#24292E;">: null,</span></span>
<span class="line"><span style="color:#24292E;">      </span><span style="color:#032F62;">&quot;finish_reason&quot;</span><span style="color:#24292E;">: </span><span style="color:#032F62;">&quot;stop&quot;</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">      </span><span style="color:#032F62;">&quot;stop_reason&quot;</span><span style="color:#24292E;">: null</span></span>
<span class="line"><span style="color:#24292E;">    }</span></span>
<span class="line"><span style="color:#24292E;">  ],</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;usage&quot;</span><span style="color:#24292E;">: {</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;prompt_tokens&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">16</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;total_tokens&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">165</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;completion_tokens&quot;</span><span style="color:#24292E;">: </span><span style="color:#005CC5;">149</span><span style="color:#24292E;">,</span></span>
<span class="line"><span style="color:#24292E;">    </span><span style="color:#032F62;">&quot;prompt_tokens_details&quot;</span><span style="color:#24292E;">: null</span></span>
<span class="line"><span style="color:#24292E;">  },</span></span>
<span class="line"><span style="color:#24292E;">  </span><span style="color:#032F62;">&quot;prompt_logprobs&quot;</span><span style="color:#24292E;">: null</span></span>
<span class="line"><span style="color:#24292E;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>当使用 <code>QwQ-32B-AWQ</code> 进行 tool 推理时候，模型的输入为：</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292E;">&lt;|im_start|&gt;system</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;"># Tools</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">You may call one or more functions to assist with the user query.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">You are provided with function signatures within &lt;</span><span style="color:#22863A;">tools</span><span style="color:#24292E;">&gt;&lt;/</span><span style="color:#22863A;">tools</span><span style="color:#24292E;">&gt; XML tags:</span></span>
<span class="line"><span style="color:#24292E;">&lt;</span><span style="color:#22863A;">tools</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"><span style="color:#24292E;">{&quot;type&quot;: &quot;function&quot;, &quot;function&quot;: {&quot;name&quot;: &quot;get_current_weather&quot;, &quot;description&quot;: &quot;Get the current weather&quot;, &quot;parameters&quot;: {&quot;type&quot;: &quot;object&quot;, &quot;properties&quot;: {&quot;location&quot;: {&quot;type&quot;: &quot;string&quot;, &quot;description&quot;: &quot;The city and state, e.g. San Francisco, CA&quot;}, &quot;format&quot;: {&quot;type&quot;: &quot;string&quot;, &quot;enum&quot;: [&quot;celsius&quot;, &quot;fahrenheit&quot;], &quot;description&quot;: &quot;The temperature unit to use. Infer this from the users location.&quot;}}, &quot;required&quot;: [&quot;location&quot;, &quot;format&quot;]}}}</span></span>
<span class="line"><span style="color:#24292E;">&lt;/</span><span style="color:#22863A;">tools</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">For each function call, return a json object with function name and arguments within &lt;</span><span style="color:#22863A;">tool_call</span><span style="color:#24292E;">&gt;&lt;/</span><span style="color:#22863A;">tool_call</span><span style="color:#24292E;">&gt; XML tags:</span></span>
<span class="line"><span style="color:#24292E;">&lt;</span><span style="color:#22863A;">tool_call</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"><span style="color:#24292E;">{&quot;name&quot;: &lt;</span><span style="color:#22863A;">function-name</span><span style="color:#24292E;">&gt;, &quot;arguments&quot;: &lt;</span><span style="color:#22863A;">args-json-object</span><span style="color:#24292E;">&gt;}</span></span>
<span class="line"><span style="color:#24292E;">&lt;/</span><span style="color:#22863A;">tool_call</span><span style="color:#24292E;">&gt;&lt;|im_end|&gt;</span></span>
<span class="line"><span style="color:#24292E;">&lt;|im_start|&gt;user</span></span>
<span class="line"><span style="color:#24292E;">what is the whether in shanghai&lt;|im_end|&gt;</span></span>
<span class="line"><span style="color:#24292E;">&lt;|im_start|&gt;assistant</span></span>
<span class="line"><span style="color:#24292E;">&lt;</span><span style="color:#22863A;">think</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对应的输出为：</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="shiki github-light" style="background-color:#fff;" tabindex="0"><code><span class="line"><span style="color:#24292E;">Okay, the user is asking for the weather in Shanghai. I need to use the get_current_weather function. Let me check the parameters required. The function needs location and format. The location here is clearly Shanghai. But the format can be either celsius or fahrenheit. The description says to infer the format based on the user&#39;s location. Since Shanghai is in China, which typically uses Celsius, I should set the format to celsius. So the arguments should be {&quot;location&quot;: &quot;Shanghai&quot;, &quot;format&quot;: &quot;celsius&quot;}. Let me make sure there are no typos. Yep, looks good. Time to put it in the tool_call format.</span></span>
<span class="line"><span style="color:#24292E;">&lt;/</span><span style="color:#22863A;">think</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#24292E;">&lt;</span><span style="color:#22863A;">tool_call</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"><span style="color:#24292E;">{&quot;name&quot;: &quot;get_current_weather&quot;, &quot;arguments&quot;: {&quot;location&quot;: &quot;Shanghai&quot;, &quot;format&quot;: &quot;celsius&quot;}}</span></span>
<span class="line"><span style="color:#24292E;">&lt;/</span><span style="color:#22863A;">tool_call</span><span style="color:#24292E;">&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>总结</li></ul><p>对于涉及 reasoning 的模型，一般还是通过 prompt 中构造 xml 来实现 reasoning 以及 tool 的使用。参考 QwQ 以及 deepseek R1 distill，似乎训练数据中有包含了对输出格式约束的案例。</p><hr><h2 id="qwen-2-5-vl" tabindex="-1"><a class="header-anchor" href="#qwen-2-5-vl" aria-hidden="true">#</a> Qwen 2.5 Vl</h2>`,112),Z={href:"https://qwenlm.github.io/zh/blog/qwen2.5-vl/",target:"_blank",rel:"noopener noreferrer"},$={href:"https://qwen.ai/blog?id=250aaecfcd4828d55be2b2437a76d66a099860da&from=research.research-list",target:"_blank",rel:"noopener noreferrer"},nn=l('<p>huggingface： https://huggingface.co/collections/Qwen/qwen25-vl-6795ffac22b334a837c0f9a5</p><p>arxiv：https://arxiv.org/abs/2502.13923</p><p>Qwen2.5-VL 的主要特点如下所示（摘抄于 qwen 博客）：</p><ul><li><strong>感知更丰富的世界</strong> ：Qwen2.5-VL 不仅擅长识别常见物体，如花、鸟、鱼和昆虫，还能够分析图像中的文本、图表、图标、图形和布局。</li></ul><figure><img src="'+F+'" alt="image-20250926191238455" tabindex="0" loading="lazy"><figcaption>image-20250926191238455</figcaption></figure><ul><li><strong>Agent</strong> ：Qwen2.5-VL 直接作为一个视觉 Agent，可以推理并动态地使用工具，初步具备了使用电脑和使用手机的能力。如告诉 agent 使用手机 QQ 给某位好友发送新年祝福。</li><li><strong>理解长视频和捕捉事件</strong> ：Qwen2.5-VL 能够理解超过 1 小时的视频，并且这次它具备了通过精准定位相关视频片段来捕捉事件的新能力。</li><li><strong>视觉定位</strong> ：Qwen2.5-VL 可以通过生成 bounding boxes 或者 points 来准确定位图像中的物体，并能够为坐标和属性提供稳定的 JSON 输出。（有点类似目标检测）</li></ul><figure><img src="'+C+'" alt="image-20250926191209997" tabindex="0" loading="lazy"><figcaption>image-20250926191209997</figcaption></figure><ul><li><strong>结构化输出</strong> ：对于发票、表单、表格等数据，Qwen2.5-VL 支持其内容的结构化输出，惠及金融、商业等领域的应用。在 Qwen2.5-VL 中设计了一种更全面的文档解析格式，称为 QwenVL HTML 格式，它既可以将文档中的文本精准地识别出来，也能够提取文档元素（如图片、表格等）的位置信息，从而准确地将文档中的版面布局进行精准还原</li></ul><figure><img src="'+k+'" alt="image-20250926191522773" tabindex="0" loading="lazy"><figcaption>image-20250926191522773</figcaption></figure><p>Qwen2.5-VL-32B 在 Qwen2.5 VL 基础上继续强化学习优化， 提升了复杂数学问题求解的准确性，回答规范性，以及图像细粒度理解与推理能力。</p><figure><img src="https://qianwen-res.oss-cn-beijing.aliyuncs.com/Qwen2.5-VL-32B/qwen2.5vl-32b-vision.jpg" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><ul><li>架构</li></ul><figure><img src="'+B+'" alt="image-20250926210340004" tabindex="0" loading="lazy"><figcaption>image-20250926210340004</figcaption></figure><ol><li>LLM：Qwen2.5-VL 采用 Qwen2.5 LLM 预训练模型进行初始化的同时，将原本的 1D RoPE 改成了 Multimodal RoPE</li><li>Vision Encoder：采用了重新设计的 ViT，并且从头开始进行训练。包括 CLIP 预训练，视觉语言对齐，端到端微调。</li></ol><p>预训练量从 Qwen2-VL 的 1.2 T，便到了 4.2 T。</p>',15),tn={href:"https://zhuanlan.zhihu.com/p/24986805514",target:"_blank",rel:"noopener noreferrer"},en=n("hr",null,null,-1),sn=n("h2",{id:"qvq-qwen-models-for-visual-reasoning",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#qvq-qwen-models-for-visual-reasoning","aria-hidden":"true"},"#"),t(" QvQ - Qwen models for visual reasoning")],-1),ln={href:"https://qwen.ai/blog?id=719d1b809d9241a4793a231d237c8791dc225160&from=research.research-list",target:"_blank",rel:"noopener noreferrer"},an=n("p",null,"huggingface：https://huggingface.co/Qwen/QVQ-72B-Preview",-1),on=n("p",null,"QVQ 基于 Qwen2-VL-72B 构建，当时在视觉理解和复杂问题解决能力上取得了一定的成果，但仍有一定的局限性。以下是部分 demo 展示。",-1),rn=n("figure",null,[n("img",{src:V,alt:"image-20251003180801340",height:"400",tabindex:"0",loading:"lazy"}),n("figcaption",null,"image-20251003180801340")],-1),pn=n("p",null,"QVQ 可以根据图片进行一些推理",-1),cn=n("figure",null,[n("img",{src:M,alt:"image-20251003180825593",height:"400",tabindex:"0",loading:"lazy"}),n("figcaption",null,"image-20251003180825593")],-1),gn={href:"https://qwen.ai/blog?id=913c68f0cf26db671f39114a6fdce48d961fc08b&from=research.research-list",target:"_blank",rel:"noopener noreferrer"},dn=l('<ol><li><strong>细致观察：抓住每一个细节</strong> QVQ-Max 对图片的解析能力非常强，无论是复杂的图表还是日常生活中随手拍的照片，它都能快速识别出关键元素。比如，它可以告诉你一张照片里有哪些物品、有什么文字标识，甚至还能指出一些你可能忽略的小细节。</li><li><strong>深入推理：不只是“看到”，还要“想到”</strong> 仅仅识别出图片里的内容还不够，QVQ-Max 还能进一步分析这些信息，并结合背景知识得出结论。例如，在一道几何题中，它可以根据题目附带的图形推导出答案；在一段视频里，它能根据画面内容推测出接下来可能发生的情节。</li><li><strong>灵活应用：从解答问题到创作</strong> 除了分析和推理，QVQ-Max 还能做一些有趣的事情，比如帮你设计插画、生成短视频脚本，甚至根据你的需求创作角色扮演的内容。如果你上传一幅草稿，它可能会帮你完善成一幅完整的作品；上传一个日常照片，它可以化身犀利的评论家，占卜师。</li></ol><p>根据官网的 demo ，QVQ-Max 包括了 thinking 部分的推理过程，支持多张图片同时推理。</p><hr><h2 id="qwen2-5-omni" tabindex="-1"><a class="header-anchor" href="#qwen2-5-omni" aria-hidden="true">#</a> Qwen2.5-Omni</h2>',4),un={href:"https://qwen.ai/blog?id=9ef8b30f398c303da67ab622204b07d6c74af9cd&from=research.research-list",target:"_blank",rel:"noopener noreferrer"},mn={href:"https://huggingface.co/Qwen/Qwen2.5-Omni-7B",target:"_blank",rel:"noopener noreferrer"},yn={href:"https://modelscope.cn/models/Qwen/Qwen2.5-Omni-7B",target:"_blank",rel:"noopener noreferrer"},hn=l('<p>arxiv：https://arxiv.org/abs/2503.20215</p><p>Qwen 推出的端到端多模态模型，能够无缝处理文本、图像、音频和视频等多种输入形式，并通过实时流式响应同时生成文本与自然语音合成输出。</p><figure><img src="'+z+'" alt="image-20251003194211288" tabindex="0" loading="lazy"><figcaption>image-20251003194211288</figcaption></figure><p>模型采用了 Thinker-Talker 的架构，LLM 用 Qwen2.5-7B，视觉 encoder 用 Qwen2.5-VL，音频编码器与 Qwen2-audio 一样用 Whisper-large-v3。</p><p>位置编码采用了 TMRoPE，将原始的 RoPE 分解成时间，高度和宽度。</p><figure><img src="'+T+'" alt="image-20251003204024670" tabindex="0" loading="lazy"><figcaption>image-20251003204024670</figcaption></figure><p>对于视频输入，为了同时处理视频和音频，相比于 MRoPE，加入了时间 ID temporal ID。</p><ol><li><p>将视频与音频的表示按 <strong>2 秒为单位</strong> 切分。在每个 2 秒片段中，先放置视频帧的表示，再放置对应的音频表示。这样保证模型能在同一时间窗口内同时接收和理解画面与声音。</p></li><li><p>视频被视为一系列图像，帧与帧之间时间 ID 按实际间隔递增。音频按 40ms 切分位置，与视频的 temporal ID 对齐。当多模态输入同时存在时，每个模态的 position ID 编号在上一个模态的最大 ID 基础上递增，避免冲突。</p></li><li><p>文本和音频使用相同的 position ID，但音频额外加入绝对时间编码（每 40ms 一个时间 ID）。</p><p>图像和视频在 height 和 width 上有独立的 position ID，而视频的 temporal ID 会随着帧率动态调整，保证 1 个时间 ID ≈ 40ms。</p></li></ol><p>在生成过程中，所有的文字内容都是由 thinker 生成，生成方式与大部分的 LLM 一样，talker 接受 text 对应 token 的 embedding，同时也接受 audio 或 视觉输入对应位置所生成的 representations。</p><ul><li>后训练</li></ul><p>后训练的 prompt template 如下</p><figure><img src="'+A+'" alt="image-20251007115502377" tabindex="0" loading="lazy"><figcaption>image-20251007115502377</figcaption></figure>',12);function qn(fn,bn){const e=i("ExternalLinkIcon");return o(),r("div",null,[R,D,O,n("p",null,[n("a",I,[t("开源模型"),s(e)]),t("，"),n("a",S,[t("官方博客 1"),s(e)]),t("，"),n("a",H,[t("官方博客 2"),s(e)])]),G,n("p",null,[n("a",W,[t("Qwen1.5 MOE"),s(e)]),t("，模型总共有 14.3 的参数，实际推理过程中，只是用到了 2.7B。")]),j,N,K,n("p",null,[n("a",Y,[t("Qwen2 Technical Report"),s(e)])]),U,n("p",null,[t("更多模型效果可以查看："),n("a",X,[t("Qwen2 官网"),s(e)])]),J,n("p",null,[t("博客："),n("a",Z,[t("Qwen2.5VL"),s(e)]),t(" , "),n("a",$,[t("Qwen2.5vl-32B"),s(e)])]),nn,n("p",null,[t("更多可以参考"),n("a",tn,[t("这篇文章"),s(e)]),t("的概括")]),en,sn,n("p",null,[t("博客: "),n("a",ln,[t("QVQ: 更睿智地看世界"),s(e)])]),an,on,rn,pn,cn,n("p",null,[t("后面推出的 "),n("a",gn,[t("QVQ-Max：有依据地思考 "),s(e)]),t(" 在理解和思考能力上有所提升，QVQ-Max 具备以下特点：")]),dn,n("p",null,[t("博客："),n("a",un,[t("Qwen2.5 Omni：看得见、听得到、会说话、能写作，样样精通！"),s(e)])]),n("p",null,[t("模型： "),n("a",mn,[t("Hugging Face"),s(e)]),t("、"),n("a",yn,[t("ModelScope"),s(e)])]),hn])}const wn=a(P,[["render",qn],["__file","笔记qwen_2.html.vue"]]);export{wn as default};
